def shortest_palindrome(s):
    if s == s[::-1]:
        return s

    rev_s = s[::-1]
    combined = s + '#' + rev_s
    prefix_function = [0] * len(combined)

    for i in range(1, len(combined)):
        j = prefix_function[i - 1]
        while j > 0 and combined[i] != combined[j]:
            j = prefix_function[j - 1]
        if combined[i] == combined[j]:
            j += 1
        prefix_function[i] = j

    longest_palindrome_suffix_length = prefix_function[-1]
    return s + rev_s[:len(s) - longest_palindrome_suffix_length]

import sys

def main():
    s = sys.stdin.readline().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
